#include <bits/stdc++.h>
using namespace std;
int mex(vector<int>v,int x){
    vector<bool>flag(100001,false);
    int mx = -1;
    for(auto i:v){
        flag[i] = 1;
        mx = max(mx,i);
    }

    long long ans = -1;
    for(int i=0;i<=mx && x>=0;i++){
        if(!flag[i]){
        ans = i;
        x--;
    }
    }

    if(x < 0)
    return ans;


    return mx+x+1;
} 

int main() {
	int n; 
	cin>>n;

	int m;
	cin>>m;

	vector<int>v;
	for(int i=0;i<n;i++){
	    int x;
	    cin>>x;
	    v.push_back(x);
	}
	cout<<mex(v,m)<<endl;	
}
